            "coord": [
              150,
              250
            ],
            "objectRadius": 40,
            "size": [
              80,
              40
            ]
          },
          {
            "key": "axis_y",
            "kind": "y_axis",
            "coord": [
              30,
              250
            ],
            "objectRadius": 0,
            "size": [
              33,
              33
            ]
          }
